parameters.jsCode:
// Build the exact JSON contract the Answer Synthesis Agent's system
// prompt expects, straight from the Guardrail Agent's parsed output.
// We do not rely on the If node passthrough alone since that only
// preserves whatever the Guardrail LLM happened to include.

const raw = $json.output;
const g = typeof raw === 'string' ? JSON.parse(raw) : raw;

return [{
  json: {
    original_question: g.original_question,
    validated_chunks: g.validated_chunks || [],
    coverage_notes: g.coverage_notes || '',
    contradiction_notes: g.contradiction_notes || '',
    low_confidence: !!g.low_confidence
  }
}];

// Pure passthrough of the current item - no $('NodeName') lookups.

const raw = $json.output;
const g = typeof raw === 'string' ? JSON.parse(raw) : raw;

return [{
  json: {
    type: 'retry',
    original_question: g.original_question,
    attempt_number: (g.attempt_number || 1) + 1,
    failed_query: g.planned_queries || [],
    rejection_reason: g.rejection_reason || {}
  }
}];

// Pure passthrough of the current item - no $('NodeName') lookups.
// The Search Agent already echoed original_question, attempt_number,
// and planned_queries forward in its own output, so we just unpack it.

const raw = $json.output;
const s = typeof raw === 'string' ? JSON.parse(raw) : raw;

return [{
  json: {
    original_question: s.original_question,
    planned_queries: s.planned_queries || [],
    search_results: {
      results: s.results || [],
      null_result_query_ids: s.null_result_query_ids || []
    },
    attempt_number: s.attempt_number || 1
  }
}];
